  function migrateV7(s) {
    if (!s.galleries.some(function (g) { return g.slug === 'mariage'; })) {
      var files = ['_DSC6081.jpg', '_DSC4819.jpg', '_DSC6358.jpg', '_DSC6209.jpg', '_DSC6239.jpg', '_DSC4931.jpg', '_DSC6235.jpg'];
      var ids = files.map(function (f) {
        var id = uid('ph');
        s.photos[id] = { id: id, gallery: 'mariage', file: f, src: 'images/' + f, faces: [], scanned: false, uploadedAt: '2026-07-03' };
        return id;
      });
      var idx = s.galleries.findIndex(function (g) { return g.slug === 'evenements'; });
      s.galleries.splice(idx < 0 ? s.galleries.length : idx, 0, {
        id: uid('g'), slug: 'mariage', name: 'mariage',
        desc: 'L\u2019\u00e9motion vraie, du oui aux derni\u00e8res lueurs du jour.',
        photoIds: ids, coverId: ids[0],
        nameEn: 'wedding', descEn: 'True emotion, from the vows to the last light of day.', subEn: null,
        private: false, clientId: null, faceSearch: false
      });
    }
    s.version = 7;
    return s;
  }

  // Migration v7 -> v8 : prestations (page contact), filigrane, téléchargement client.
  function migrateV8(s) {
    if (!s.services) {
      var fresh = seed();
      s.services = fresh.services;
    }
    if (typeof s.settings.watermark === 'undefined') s.settings.watermark = false;
    (s.clients || []).forEach(function (c) { if (typeof c.canDownload === 'undefined') c.canDownload = false; });
    s.version = 8;
    return s;
  }

  // Amorce unique des photos de coulisses (page à propos) pour les états déjà enregistrés.
  function ensureBackstage(s) {
    try {
      if (s.about && !s.about.backstageSeeded) {
        if (!s.about.backstage || !s.about.backstage.length) {
          s.about.backstage = ['images/_DSC6209.jpg', 'images/L1220728.jpg', 'images/DSC08766.jpg'];
        }
        s.about.backstageSeeded = true;
        try { localStorage.setItem(KEY, JSON.stringify(s)); } catch (e2) {}
      }
    } catch (e) {}
  }

  function load() {
    try {
      var raw = localStorage.getItem(KEY);
      if (raw) {
        var s = JSON.parse(raw);
        if (s && s.version === 8) { ensureBackstage(s); return s; }
        // Migrations en chaîne v6 -> v7 -> v8, sans toucher au contenu existant.
        if (s && (s.version === 6 || s.version === 7)) {
          var ms = s.version === 6 ? migrateV7(s) : s;
          ms = migrateV8(ms);
          try { localStorage.setItem(KEY, JSON.stringify(ms)); } catch (e2) {}
          return ms;
        }
      }
    } catch (e) {}
    var fresh = seed();
    try { localStorage.setItem(KEY, JSON.stringify(fresh)); } catch (e) {}
    return fresh;
  }

  function save() {
    try { localStorage.setItem(KEY, JSON.stringify(state)); }
    catch (e) {
      // Quota dépassé : typiquement trop de photos en base64 (mode démo).
      console.warn('NVStore: sauvegarde locale impossible (quota dépassé ?). Activez le stockage externe des photos — voir docs/MIGRATION.md.', e);
      setStatus('quota');
    }
    if (backend && !applyingRemote) {
      try { backend.push(state); } catch (e) { console.warn('NVStore: push distant échoué', e); }
    }
  }

  function emit() { listeners.forEach(function (cb) { try { cb(state); } catch (e) {} }); }

  // Sauvegarde différée : le re-render (emit) part immédiatement, la
  // sérialisation localStorage (lourde avec des photos en base64) suit.
  var saveT = null;
  function scheduleSave() {
    if (saveT) clearTimeout(saveT);
    saveT = setTimeout(function () { saveT = null; save(); }, 120);
  }
  window.addEventListener('pagehide', function () {
    if (saveT) { clearTimeout(saveT); saveT = null; save(); }
  });

  // cross-tab / cross-page sync
  window.addEventListener('storage', function (e) {
    if (e.key === KEY && e.newValue) { try { state = JSON.parse(e.newValue); emit(); } catch (x) {} }
  });

  state = load();

  var NVStore = {
    get: function () { return state; },
    subscribe: function (cb) { listeners.push(cb); return function () { listeners = listeners.filter(function (x) { return x !== cb; }); }; },
    update: function (fn) { fn(state); emit(); scheduleSave(); },
    save: function () { save(); emit(); },
    // Re-render tous les abonnés sans rien sauvegarder (utilisé par le changement de langue).
    ping: function () { emit(); },
    reset: function () {
      try { localStorage.removeItem(KEY); } catch (e) {}
      state = load();
      if (backend && backend.push) { try { backend.push(state); } catch (e) {} }
      emit();
    },
    // Appelé par l'adaptateur distant (hydratation + temps réel) pour remplacer
    // l'état local sans le re-pousser vers la base.
    _ingest: function (incoming) {
      if (!incoming) return;
      applyingRemote = true;
      state = incoming;
      try { localStorage.setItem(KEY, JSON.stringify(state)); } catch (e) {}
      applyingRemote = false;
      emit();
    },
    uid: uid,
    // État de synchronisation : valeur courante + abonnement.
    syncStatus: function () { return syncStatus; },
    onSyncStatus: function (cb) {
      statusListeners.push(cb);
      return function () { statusListeners = statusListeners.filter(function (x) { return x !== cb; }); };
    },
    photo: function (id) { return state.photos[id]; },
    gallery: function (id) { return state.galleries.find(function (g) { return g.id === id; }); },
    gallleryBySlug: function (slug) { return state.galleries.find(function (g) { return g.slug === slug; }); },
    client: function (id) { return state.clients.find(function (c) { return c.id === id; }); },
    publicGalleries: function () { return state.galleries.filter(function (g) { return !g.private; }); },
    clientGalleries: function (clientId) {
      var c = this.client(clientId); if (!c) return [];
      return c.galleryIds.map(function (id) { return state.galleries.find(function (g) { return g.id === id; }); }).filter(Boolean);
    },
    resolveSrc: function (p) {
      if (!p) return '';
      var src = (typeof p === 'string') ? p : (p.src || (p.file ? 'images/' + p.file : ''));
      if (!src) return '';
      // URL absolue / data: / blob: -> telle quelle.
      if (/^(https?:|data:|blob:)/i.test(src)) return src;
      // Chemin court (ex. "mariage/img.jpg") -> préfixe le stockage externe si défini.
      var base = (window.NV_CONFIG && window.NV_CONFIG.storage && window.NV_CONFIG.storage.baseUrl) || '';
      if (base) return base.replace(/\/+$/, '') + '/' + src.replace(/^\/+/, '');
      return src;
    }
  };
  window.NVStore = NVStore;

  // En mode distant, on attache l'adaptateur : il hydrate le cache depuis la base,
  // écoute le temps réel, et reçoit les écritures via save() -> backend.push().
  // En mode local (défaut), rien de tout ceci ne s'exécute.
  if (REMOTE && window.NVBackend && typeof window.NVBackend.create === 'function') {
    try {
      backend = window.NVBackend.create({
        config: CFG,
        getState: function () { return state; },
        ingest: function (s) { NVStore._ingest(s); },
        onStatus: setStatus,
        seed: seed
      });
      if (backend && backend.start) backend.start();
    } catch (e) {
      console.warn('NVStore: adaptateur distant indisponible, mode local.', e);
      backend = null;
    }
  }
